import React from 'react';
import styled from 'styled-components';

const SectionTitle = styled.h4`
  font-size: 12pt;
  line-height: 12pt;
  position: relative;
  margin-bottom: .1in;
  width: 100%;
  border-bottom: solid 1px #000;

  @media (max-width: 900px) {
    font-size: 9pt;
    line-height: 9pt;
    margin-bottom: .025in;
  }
  @media (max-width: 660px) {
    font-size: 8pt;
    line-height: 8pt;
    margin-bottom: .05in;
  }
  @media print {
    font-size: 12pt;
    line-height: 12pt;
    margin-bottom: .1in;
  }
`;

const SectionContent = styled.div`
  margin: 0in 0in 0in .25in;

  @media (max-width: 900px) {
    margin: 0in 0in 0in .2in;
  }
  @media (max-width: 660px) {
    margin: 0in 0in 0in .125in;
  }
  @media print {
    margin: 0in 0in 0in .25in;
  }
`;

const TitleBar = styled.div`
  position: relative;
  height: 11pt;
  margin-bottom: .05in;
  line-height: 11pt;
  font-size: 11pt;
  font-weight: 500;

  @media (max-width: 900px) {
    height: 9pt;
    margin-bottom: .075in;
    line-height: 9pt;
    font-size: 9pt;
  }
  @media (max-width: 660px) {
    height: 6pt;
    margin-bottom: .05in;
    line-height: 6pt;
    font-size: 6pt;
  }
  @media print {
    height: 11pt;
    margin-bottom: .05in;
    line-height: 11pt;
    font-size: 11pt;
  }
`;

const DegreeTitle = styled.div`
  position: absolute;
`;

const DateRange = styled.div`
  position: absolute;
  right: 0;
`;

export const Education = ({ degrees }) => {
  return (
    <section>
      <SectionTitle>Education</SectionTitle>
      <SectionContent>
        {degrees.map((degree, index) => (
          <TitleBar key={index}>
            <DegreeTitle>{degree.degree} - {degree.school}</DegreeTitle>
            <DateRange>{degree.date}</DateRange>
          </TitleBar>
        ))}
      </SectionContent>
    </section>
  );
};
